What will be the effect of the following block if no row exists for employee_id = 1000?

Code:
SET SERVEROUTPUT ON
BEGIN
  UPDATE employees
  SET salary = salary + 100
  WHERE employee_id = 1000;
  DBMS_OUTPUT.PUT_LINE(SQL%ROWCOUNT);
END;

What does the following PL/SQL block display? The departments table exists and is populated.

Code:
SET SERVEROUTPUT ON
DECLARE
  x VARCHAR2(10);
  CURSOR c IS SELECT department_id FROM departments WHERE ROWNUM <= 1;
  v_id departments.department_id%TYPE;
BEGIN
  OPEN c;
  FETCH c INTO v_id;
  IF c%FOUND THEN
    DBMS_OUTPUT.PUT_LINE('X');
  END IF;
  DBMS_OUTPUT.PUT_LINE('Z');
  CLOSE c;
EXCEPTION
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Y');
END;

What will the following PL/SQL block display? The employees table exists and contains all three employees.

Code:
SET SERVEROUTPUT ON
DECLARE
  TYPE t_ids IS TABLE OF employees.employee_id%TYPE;
  v_ids t_ids := t_ids(101,102,103);
BEGIN
  FORALL i IN v_ids.FIRST .. v_ids.LAST
    UPDATE employees
    SET salary = salary + 50
    WHERE employee_id = v_ids(i);
  DBMS_OUTPUT.PUT_LINE(SQL%ROWCOUNT);
END;

